  2→import React, { Suspense, lazy, useState, useEffect, useRef } from 'react';
  3→import { Screen, DataPoint, ContributionMode } from './types';
  4→import { getSession, signOut } from './lib/client/auth';
  5→import { flushOfflineQueue } from './lib/client/offlineQueue';
  6→import { sendSubmissionPayload } from './lib/client/submissionSync';
  7→import Splash from './components/Screens/Splash';
  8→import Home from './components/Screens/Home';
  9→import Navigation from './components/Navigation';
 10→import ErrorBoundary from './components/ErrorBoundary';
 11→
 12→const Details = lazy(() => import('./components/Screens/Details'));
 13→const Auth = lazy(() => import('./components/Screens/Auth'));
 14→const ContributionFlow = lazy(() => import('./components/Screens/ContributionFlow'));
 15→const Profile = lazy(() => import('./components/Screens/Profile'));
 16→const Analytics = lazy(() => import('./components/Screens/Analytics'));
 17→const Settings = lazy(() => import('./components/Screens/Settings'));
 18→const QualityInfo = lazy(() => import('./components/Screens/QualityInfo'));
 19→const RewardsCatalog = lazy(() => import('./components/Screens/RewardsCatalog'));
 20→const AdminQueue = lazy(() => import('./components/Screens/AdminQueue'));
 21→
 22→interface WindowWithIdleCallback extends Window {
 23→  requestIdleCallback?: (callback: IdleRequestCallback, options?: IdleRequestOptions) => number;
 24→  cancelIdleCallback?: (handle: number) => void;
 25→}
 26→
 27→const App: React.FC = () => {
 28→  const isSyncingRef = useRef(false);
 29→  const [currentScreen, setCurrentScreen] = useState<Screen>(Screen.SPLASH);
 30→  const [selectedPoint, setSelectedPoint] = useState<DataPoint | null>(null);
 31→  const [isOffline, setIsOffline] = useState(false);
 32→  const [isAuthenticated, setIsAuthenticated] = useState(false);
 33→  const [isAdmin, setIsAdmin] = useState(false);
 34→  const [language, setLanguage] = useState<'en' | 'fr'>(() => {
 35→    const saved = localStorage.getItem('adl_language');
 36→    return saved === 'en' ? 'en' : 'fr';
 37→  });
 38→  const [history, setHistory] = useState<Screen[]>([]);
 39→  const [authReturnScreen, setAuthReturnScreen] = useState<Screen>(Screen.SPLASH);
 40→  const [contributionMode, setContributionMode] = useState<ContributionMode>('CREATE');
 41→  const [contributionPoint, setContributionPoint] = useState<DataPoint | null>(null);
 42→  const t = (en: string, fr: string) => (language === 'fr' ? fr : en);
 43→
 44→  const navigateTo = (screen: Screen, point: DataPoint | null = null) => {
 45→    if (currentScreen === Screen.SPLASH && screen !== Screen.SPLASH) {
 46→      localStorage.setItem("adl_splash_seen", "true");
 47→    }
 48→    if (screen === Screen.AUTH) {
 49→      setAuthReturnScreen(currentScreen);
 50→    }
 51→    setHistory(prev => [...prev, currentScreen]);
 52→    setCurrentScreen(screen);
 53→    if (point) setSelectedPoint(point);
 54→  };
 55→
 56→  const goBack = () => {
 57→    if (history.length > 0) {
 58→      const prev = history[history.length - 1];
 59→      setHistory(prevHistory => prevHistory.slice(0, -1));
 60→      setCurrentScreen(prev);
 61→      return;
 62→    }
 63→    if (currentScreen === Screen.AUTH) {
 64→      setCurrentScreen(authReturnScreen);
 65→      return;
 66→    }
 67→    // Fallback for screens opened via tab navigation (no history).
 68→    setHistory([]);
 69→    setCurrentScreen(Screen.HOME);
 70→  };
 71→
 72→  const switchTab = (screen: Screen) => {
 73→    setHistory([]);
 74→    if (screen === Screen.CONTRIBUTE && !isAuthenticated) {
 75→      setAuthReturnScreen(currentScreen);
 76→      setCurrentScreen(Screen.AUTH);
 77→    } else {
 78→      if (screen === Screen.AUTH) {
 79→        setAuthReturnScreen(currentScreen);
 80→      }
 81→      if (screen === Screen.CONTRIBUTE) {
 82→        setContributionMode('CREATE');
 83→        setContributionPoint(null);
 84→      }
 85→      setCurrentScreen(screen);
 86→    }
 87→  };
 88→
 89→  const openContribution = (mode: ContributionMode, point: DataPoint | null = null) => {
 90→    setContributionMode(mode);
 91→    setContributionPoint(point);
 92→    if (isAuthenticated) {
 93→      navigateTo(Screen.CONTRIBUTE);
 94→      return;
 95→    }
 96→    navigateTo(Screen.AUTH);
 97→  };
 98→
 99→  useEffect(() => {
100→    localStorage.setItem('adl_language', language);
101→    document.documentElement.lang = language;
102→  }, [language]);
103→
104→  useEffect(() => {
105→    const handleStatus = async () => {
106→      const online = navigator.onLine;
107→      setIsOffline(!online);
108→      if (online) {
109→        const runSync = async () => {
110→          if (isSyncingRef.current) return;
111→          isSyncingRef.current = true;
112→          try {
113→            await flushOfflineQueue(sendSubmissionPayload);
114→          } catch (error) {
115→            console.error('[App] Offline queue sync failed:', error);
116→          } finally {
117→            isSyncingRef.current = false;
118→          }
119→        };
120→        const windowWithIdle = window as WindowWithIdleCallback;
121→        if (typeof windowWithIdle.requestIdleCallback === 'function') {
122→          windowWithIdle.requestIdleCallback(() => {
123→            void runSync();
124→          }, { timeout: 2000 });
125→        } else {
126→          window.setTimeout(() => {
127→            void runSync();
128→          }, 0);
129→        }
130→      }
131→    };
132→    window.addEventListener('online', handleStatus);
133→    window.addEventListener('offline', handleStatus);
134→    void handleStatus();
135→    return () => {
136→      window.removeEventListener('online', handleStatus);
137→      window.removeEventListener('offline', handleStatus);
138→    };
139→  }, []);
140→
141→  const refreshSession = async () => {
142→    const session = await getSession();
143→    const hasUser = !!session?.user;
144→    setIsAuthenticated(hasUser);
145→    setIsAdmin(Boolean(session?.user?.isAdmin));
146→    return hasUser;
147→  };
148→
149→  useEffect(() => {
150→    const bootstrap = async () => {
151→      const hasUser = await refreshSession();
152→      const hasSeenSplash = localStorage.getItem("adl_splash_seen") === "true";
153→      if (currentScreen === Screen.SPLASH && (hasUser || hasSeenSplash)) {
154→        setHistory([]);
155→        setCurrentScreen(Screen.HOME);
156→      }
157→    };
158→    bootstrap();
159→  }, []);
160→
161→  useEffect(() => {
162→    const hasSeenSplash = localStorage.getItem("adl_splash_seen") === "true";
163→    if (currentScreen === Screen.SPLASH && hasSeenSplash) {
164→      setHistory([]);
165→      setCurrentScreen(Screen.HOME);
166→    }
167→  }, [currentScreen]);
168→
169→  const renderScreen = () => {
170→    switch (currentScreen) {
171→      case Screen.SPLASH:
172→        return <Splash onStart={(scr) => navigateTo(scr)} language={language} />;
173→      case Screen.HOME:
174→        return (
175→          <Home
176→            onSelectPoint={(p) => navigateTo(Screen.DETAILS, p)}
177→            isAuthenticated={isAuthenticated}
178→            isAdmin={isAdmin}
179→            onAuth={() => navigateTo(Screen.AUTH)}
180→            onContribute={() => openContribution('CREATE')}
181→            onProfile={() => switchTab(Screen.PROFILE)}
182→            language={language}
183→          />
184→        );
185→      case Screen.DETAILS:
186→        return (
187→          <Details
188→            point={selectedPoint}
189→            onBack={goBack}
190→            onEnrich={() => openContribution('ENRICH', selectedPoint)}
191→            onAddNew={() => openContribution('CREATE')}
192→            isAuthenticated={isAuthenticated}
193→            onAuth={() => navigateTo(Screen.AUTH)}
194→            language={language}
195→          />
196→        );
197→      case Screen.AUTH:
198→        return <Auth language={language} onBack={goBack} onComplete={async () => { await refreshSession(); switchTab(Screen.HOME); }} />;
199→      case Screen.CONTRIBUTE:
200→        return (
201→          <ContributionFlow
202→            language={language}
203→            onBack={goBack}
204→            onComplete={() => switchTab(Screen.HOME)}
205→            mode={contributionMode}
206→            seedPoint={contributionPoint}
207→          />
208→        );
209→      case Screen.PROFILE:
210→        return <Profile language={language} onBack={goBack} onSettings={() => navigateTo(Screen.SETTINGS)} onRedeem={() => navigateTo(Screen.REWARDS)} />;
211→      case Screen.ANALYTICS:
212→        return (
213→          <Analytics
214→            onBack={goBack}
215→            isAdmin={isAdmin}
216→            onAdmin={isAdmin ? () => navigateTo(Screen.ADMIN) : undefined}
217→            language={language}
218→          />
219→        );
220→      case Screen.SETTINGS:
221→        return (
222→          <Settings
223→            onBack={goBack}
224→            language={language}
225→            onLanguageChange={setLanguage}
226→            onLogout={async () => {
227→              try {
228→                await signOut();
229→              } catch {
230→                // Fallback to local logout even if server sign-out fails.
231→              } finally {
232→                await refreshSession();
233→                setIsAuthenticated(false);
234→                switchTab(Screen.SPLASH);
235→              }
236→            }}
237→          />
238→        );
239→      case Screen.QUALITY:
240→        return <QualityInfo language={language} onBack={goBack} />;
241→      case Screen.REWARDS:
242→        return <RewardsCatalog language={language} onBack={goBack} />;
243→      case Screen.ADMIN:
244→        return <AdminQueue language={language} onBack={goBack} />;
245→      default:
246→        return <Splash onStart={(scr) => navigateTo(scr)} language={language} />;
247→    }
248→  };
249→
250→  return (
251→    <ErrorBoundary>
252→    <div className="app-shell flex flex-col w-full max-w-md mx-auto bg-white shadow-2xl relative overflow-hidden border-x border-gray-100">
253→      {isOffline && (
254→        <div className="bg-amber-600 text-white text-[10px] font-bold py-1.5 px-4 text-center z-50 tracking-widest uppercase">
255→          {t('Offline Mode • Local Sync Active', 'Mode hors ligne • Sync locale active')}
256→        </div>
257→      )}
258→
259→      <main className="flex-1 overflow-hidden relative">
260→        <Suspense
261→          fallback={
262→            <div className="h-full w-full bg-[#f9fafb] p-4">
263→              <div className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm text-xs text-gray-500">
264→                {t('Loading screen...', 'Chargement de l\'ecran...')}
265→              </div>
266→            </div>
267→          }
268→        >
269→          {renderScreen()}
270→        </Suspense>
271→      </main>
272→
273→      {!([Screen.SPLASH, Screen.AUTH, Screen.CONTRIBUTE].includes(currentScreen)) && (
274→        <Navigation
275→          currentScreen={currentScreen}
276→          onNavigate={(scr) => switchTab(scr)}
277→          isAuthenticated={isAuthenticated}
278→          isAdmin={isAdmin}
279→          language={language}
280→        />
281→      )}
282→    </div>
283→    </ErrorBoundary>
284→  );
285→};
286→
287→export default App;
